// $json sekarang berisi data JSON yang sudah bersih
const data = $json;

// Helper function (dari kode lama Anda, ini bagus)
const safeArray = (x) =>
  Array.isArray(x) && x.length > 0 ? x.join(", ") : "-";

const cat = data.category || {};

// Buat pesan Telegram dengan field-field BARU
const msg = `
📌 *Keyword IT*
${safeArray(data.it_keywords)}

🎓 *Keyword Mengajar*
${safeArray(data.teaching_keywords)}

📂 *Kategori*
DevOps: ${safeArray(cat.devops)}
Backend: ${safeArray(cat.backend)}
Frontend: ${safeArray(cat.frontend)}
Security: ${safeArray(cat.cybersecurity || cat.security)}
Cloud: ${safeArray(cat.cloud)}
Networking: ${safeArray(cat.networking)}

⭐ *Skor Teknis IT:* ${data.it_difficulty_score || "-"}
⭐ *Skor Mengajar:* ${data.teaching_score || "-"}

📝 *Ringkasan:*
${data.summary || "-"}
`;

return [{
  json: { telegram_text: msg }
}];

let html = $json.body || $json.data || $json.html || "";

// 1. Remove scripts, styles, metadata
html = html
  .replace(/<script[\s\S]*?<\/script>/gi, '')
  .replace(/<style[\s\S]*?<\/style>/gi, '')
  .replace(/<meta[\s\S]*?>/gi, '')
  .replace(/<head[\s\S]*?<\/head>/gi, '');

// 2. Convert <li> to dash bullet text
html = html
  .replace(/<li[^>]*>/gi, '\n- ')
  .replace(/<\/li>/gi, '');

// 3. Convert paragraph & breaks to newline
html = html
  .replace(/<\/p>/gi, '\n')
  .replace(/<br\s*\/?>/gi, '\n')
  .replace(/<\/div>/gi, '\n');

// 4. Remove all other HTML tags
html = html.replace(/<[^>]+>/g, ' ');

// 5. Remove page numbers often found in PDF → HTML
html = html.replace(/Page \d+ of \d+/gi, '');
html = html.replace(/\bPage\s*\d+\b/gi, '');
html = html.replace(/^\s*\d+\s*$/gm, ''); // single-number lines

// 6. Remove repeated header/footer lines (common in PDFs)
html = html.replace(/Curriculum Vitae|Resume|CV/gi, (m) => `\n${m}\n`); 
html = html.replace(/©.*\n/gi, '');
html = html.replace(/All rights reserved.*/gi, '');

// 7. Decode HTML entities
html = html
  .replace(/&nbsp;/g, ' ')
  .replace(/&amp;/g, '&')
  .replace(/&lt;/g, '<')
  .replace(/&gt;/g, '>')
  .replace(/&quot;/g, '"')
  .replace(/&#39;/g, "'");

// 8. Normalize whitespace & line breaks
html = html
  .replace(/\n\s*\n\s*\n+/g, '\n\n')
  .replace(/[ \t]+/g, ' ')
  .replace(/\s+\n/g, '\n')
  .replace(/\n\s+/g, '\n')
  .trim();

return [{
  json: {
    clean_text: html
  }
}];

// 1. Ambil teks mentah dari Gemini
const rawText = $json.text;

// 2. Temukan string JSON di dalam ```json ... ```
const jsonMatch = rawText.match(/\{([\s\S]*)\}/);

// 3. Cek jika JSON ditemukan
if (!jsonMatch || !jsonMatch[0]) {
  throw new Error("Tidak dapat menemukan JSON dalam output AI.");
}

const jsonString = jsonMatch[0];

// 4. Ubah string menjadi objek JSON yang sesungguhnya
try {
  const jsonData = JSON.parse(jsonString);
  // Kembalikan objek JSON agar node berikutnya bisa pakai
  return [{ json: jsonData }];
} catch (error) {
  throw new Error("Gagal mem-parsing JSON: " + error.message);
}
